package com.cho2hand.marketplace.entity.chat; import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="conversations") public class Conversation { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="conversation_id") private Long id; @Column(name="listing_id") private Long listingId; @Column(name="buyer_user_id") private Long buyerUserId; @Column(name="seller_user_id") private Long sellerUserId; private String status; @Column(name="last_message_at") private Instant lastMessageAt; @Column(name="created_at") private Instant createdAt; @Column(name="updated_at") private Instant updatedAt; @PrePersist void created(){createdAt=updatedAt=Instant.now();status="OPEN";} @PreUpdate void updated(){updatedAt=Instant.now();} public Long getId(){return id;} public Long getListingId(){return listingId;} public void setListingId(Long v){listingId=v;} public Long getBuyerUserId(){return buyerUserId;} public void setBuyerUserId(Long v){buyerUserId=v;} public Long getSellerUserId(){return sellerUserId;} public void setSellerUserId(Long v){sellerUserId=v;} public Instant getLastMessageAt(){return lastMessageAt;} public void setLastMessageAt(Instant v){lastMessageAt=v;} }
